INSERT IGNORE INTO email_templates (name, display_name, subject, html_content, text_content, variables, description, is_custom) VALUES
('new_order', 'إشعار طلب جديد', '🛍️ طلب جديد #{{orderNumber}}', '<tr><td style="background: linear-gradient(135deg, #00d25e 0%, #00a84d 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">طلب جديد! 🎉</h1></td></tr><tr><td style="padding: 40px;"><p style="font-size: 16px; color: #374151;">لديك طلب جديد من <strong>{{customerName}}</strong></p><div style="background: #f3f4f6; padding: 20px; border-radius: 8px;"><p style="margin: 0; font-size: 24px; font-weight: bold; color: #00d25e;">#{{orderNumber}}</p></div><p>الإجمالي: {{totalAmount}} ر.س</p></td></tr>', 'طلب جديد من {{customerName}} - #{{orderNumber}} - الإجمالي: {{totalAmount}} ر.س', '["orderNumber","customerName","totalAmount","items"]', 'يُرسل للتاجر عند إنشاء طلب جديد', 0),
('order_status_changed', 'تحديث حالة الطلب', '📦 تحديث حالة الطلب #{{orderNumber}}', '<tr><td style="background: linear-gradient(135deg, #6366f1 0%, #4f46e5 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">تحديث حالة الطلب</h1></td></tr><tr><td style="padding: 40px;"><p>طلب <strong>{{customerName}}</strong> تم تحديثه</p><p style="font-size: 24px; font-weight: bold; color: #6366f1;">#{{orderNumber}}</p><p>{{statusMessage}}</p></td></tr>', 'تحديث الطلب #{{orderNumber}} - {{statusMessage}}', '["orderNumber","customerName","oldStatus","newStatus","statusMessage"]', 'يُرسل للعميل عند تغيير حالة الطلب', 0),
('new_customer_message', 'رسالة جديدة من عميل', '💬 رسالة جديدة من {{customerName}}', '<tr><td style="background: linear-gradient(135deg, #8b5cf6 0%, #7c3aed 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">رسالة جديدة! 💬</h1></td></tr><tr><td style="padding: 40px;"><p><strong>{{customerName}}</strong> - {{customerPhone}}</p><div style="background: white; border: 2px solid #e5e7eb; padding: 20px; border-radius: 8px;"><p>{{message}}</p></div></td></tr>', 'رسالة جديدة من {{customerName}} ({{customerPhone}}): {{message}}', '["customerName","customerPhone","message","conversationId"]', 'يُرسل للتاجر عند استلام رسالة جديدة', 0),
('scheduled_report', 'تقرير دوري', '📊 {{reportTitle}} - {{period}}', '<tr><td style="background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">{{reportTitle}} 📊</h1></td></tr><tr><td style="padding: 40px;"><p>الطلبات: {{totalOrders}} | الإيرادات: {{totalRevenue}} ر.س | عملاء جدد: {{newCustomers}} | المحادثات: {{conversations}}</p></td></tr>', '{{reportTitle}} - الطلبات: {{totalOrders}} الإيرادات: {{totalRevenue}} عملاء جدد: {{newCustomers}}', '["reportTitle","period","totalOrders","totalRevenue","newCustomers","conversations"]', 'تقرير دوري يُرسل للتاجر', 0),
('payment_failed', 'فشل الدفع', '⚠️ فشل عملية الدفع', '<tr><td style="background: linear-gradient(135deg, #ef4444 0%, #dc2626 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">⚠️ فشل عملية الدفع</h1></td></tr><tr><td style="padding: 40px;"><p>مرحباً <strong>{{merchantName}}</strong></p><p>فشلت عملية الدفع للطلب #{{orderNumber}} بمبلغ {{amount}} ر.س</p><p>السبب: {{errorMessage}}</p></td></tr>', 'فشل الدفع للطلب #{{orderNumber}} بمبلغ {{amount}} ر.س - السبب: {{errorMessage}}', '["merchantName","amount","errorMessage","orderNumber"]', 'يُرسل للتاجر عند فشل عملية دفع', 0),
('integration_connected', 'تكامل جديد', '🔗 تم ربط {{integrationName}} بنجاح', '<tr><td style="background: linear-gradient(135deg, #10b981 0%, #059669 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">🔗 تكامل جديد</h1></td></tr><tr><td style="padding: 40px;"><p>مرحباً <strong>{{merchantName}}</strong></p><p>تم ربط <strong>{{integrationName}}</strong> بنجاح</p><p>تاريخ الربط: {{connectedAt}}</p></td></tr>', 'تم ربط {{integrationName}} بنجاح - {{connectedAt}}', '["merchantName","integrationName","connectedAt"]', 'يُرسل للتاجر عند ربط تكامل جديد', 0),
('sync_error', 'خطأ في المزامنة', '⚠️ خطأ في مزامنة {{syncType}}', '<tr><td style="background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">⚠️ خطأ في المزامنة</h1></td></tr><tr><td style="padding: 40px;"><p>مرحباً <strong>{{merchantName}}</strong></p><p>خطأ في مزامنة <strong>{{syncType}}</strong></p><p>{{errorMessage}}</p></td></tr>', 'خطأ في مزامنة {{syncType}}: {{errorMessage}}', '["merchantName","syncType","errorMessage","timestamp"]', 'يُرسل عند حدوث خطأ في المزامنة', 0),
('low_stock_alert', 'تنبيه نقص المخزون', '📦 تنبيه: نقص مخزون {{productName}}', '<tr><td style="background: linear-gradient(135deg, #f59e0b 0%, #d97706 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">📦 تنبيه نقص المخزون</h1></td></tr><tr><td style="padding: 40px;"><p>مرحباً <strong>{{merchantName}}</strong></p><p>المخزون المتبقي من <strong>{{productName}}</strong> أقل من الحد الأدنى</p><p style="font-size: 24px; color: #f59e0b;">{{currentStock}} وحدة (الحد الأدنى: {{minStock}})</p></td></tr>', 'نقص مخزون {{productName}} - المتبقي: {{currentStock}} (الحد الأدنى: {{minStock}})', '["merchantName","productName","currentStock","minStock"]', 'يُرسل عند نقص مخزون منتج', 0),
('new_review', 'تقييم جديد', '⭐ تقييم جديد من {{customerName}}', '<tr><td style="background: linear-gradient(135deg, #fbbf24 0%, #f59e0b 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">⭐ تقييم جديد</h1></td></tr><tr><td style="padding: 40px;"><p>مرحباً <strong>{{merchantName}}</strong></p><p>تقييم من <strong>{{customerName}}</strong> للمنتج {{productName}}</p><p style="font-size: 48px;">{{rating}}</p><p>{{comment}}</p></td></tr>', 'تقييم جديد من {{customerName}} - {{rating}} - {{comment}}', '["merchantName","customerName","rating","comment","productName"]', 'يُرسل عند استلام تقييم جديد', 0),
('campaign_sent', 'إرسال حملة', '📢 تم إرسال حملة {{campaignName}}', '<tr><td style="background: linear-gradient(135deg, #3b82f6 0%, #2563eb 100%); padding: 30px; text-align: center;"><h1 style="color: white; margin: 0; font-size: 28px;">📢 تم إرسال الحملة</h1></td></tr><tr><td style="padding: 40px;"><p>مرحباً <strong>{{merchantName}}</strong></p><p>حملة: <strong>{{campaignName}}</strong></p><p>المرسل إليهم: {{recipientsCount}} | نجح: {{successCount}} | فشل: {{failedCount}}</p></td></tr>', 'تم إرسال حملة {{campaignName}} - نجح: {{successCount}} فشل: {{failedCount}}', '["merchantName","campaignName","recipientsCount","successCount","failedCount"]', 'يُرسل عند إرسال حملة تسويقية', 0);
